let temperature = Math.floor(Math.random() * (35 - 22 + 1)) + 22;
let humidity = Math.floor(Math.random() * (80 - 40 + 1)) + 40;
let motion = Math.random() > 0.7 ? "DETECTED" : "NO_MOTION";
let light = Math.floor(Math.random() * (100 - 0 + 1)) + 0;

msg.topic = "home/bedroom/telemetry";

msg.payload = {
    device_id: "bedroom_controller_01",
    room: "bedroom",
    temperature: temperature,
    humidity: humidity,
    motion: motion,
    light_level: light
};

return msg;

let temperature = Math.floor(Math.random() * (45 - 25 + 1)) + 25;

let gas = Math.random() > 0.85 ? "GAS_LEAK" : "NORMAL";

let smoke = Math.random() > 0.90 ? "SMOKE_DETECTED" : "NORMAL";

msg.topic = "home/kitchen/telemetry";

msg.payload = {
    device_id: "kitchen_controller_01",
    room: "kitchen",
    temperature: temperature,
    gas_status: gas,
    smoke_status: smoke
};

return msg;

let temperature = Math.floor(Math.random() * (34 - 23 + 1)) + 23;

let motion = Math.random() > 0.6 ? "DETECTED" : "NO_MOTION";

let light = Math.floor(Math.random() * (100 - 0 + 1)) + 0;

msg.topic = "home/hall/telemetry";

msg.payload = {
    device_id: "hall_controller_01",
    room: "hall",
    temperature: temperature,
    motion: motion,
