};

return msg;

let motion = Math.random() > 0.8 ? "DETECTED" : "NO_MOTION";

let door_status = Math.random() > 0.9 ? "OPEN" : "CLOSED";

msg.topic = "home/security/telemetry";

msg.payload = {
    device_id: "security_controller_01",
    area: "main_door",
    motion: motion,
    door_status: door_status
};

return msg;

let mode = global.get("bedroom_mode") || "AUTO";

node.warn("MODE = " + mode);

if (mode !== "AUTO") {
    return null;
}
let temp = msg.payload.temperature;
let motion = msg.payload.motion;
let light = msg.payload.light_level;

let messages = [];

// FAN AUTOMATION

if (temp > 30) {
    messages.push({
        topic: "home/bedroom/fan/set",
        payload: "ON"
    });
}

if (temp < 28) {
    messages.push({
        topic: "home/bedroom/fan/set",
        payload: "OFF"
    });
}

// LIGHT AUTOMATION

if (motion === "DETECTED" && light < 40) {
    messages.push({
        topic: "home/bedroom/light/set",
        payload: "ON"
    });
}

if (motion === "NO_MOTION") {
    messages.push({
        topic: "home/bedroom/light/set",
        payload: "OFF"
    });
}

// AC AUTOMATION

if (temp > 25) {
    messages.push({
        topic: "home/bedroom/ac/set",
        payload: "ON"
    });
}

if (temp < 20) {
    messages.push({
        topic: "home/bedroom/ac/set",
        payload: "OFF"
    });
}

return [messages];

let mode = global.get("hall_mode") || "AUTO";

node.warn("MODE = " + mode);

if (mode !== "AUTO") {
    return null;
}

let motion = msg.payload.motion;
let light = msg.payload.light_level;

if(motion === "DETECTED" && light < 40){

    msg.topic = "home/hall/light/set";
    msg.payload = "ON";

    return msg;
}

if(motion === "NO_MOTION"){

    msg.topic = "home/hall/light/set";
    msg.payload = "OFF";

    return msg;
}

return null;

let mode = global.get("kitchen_mode") || "AUTO";

if (mode !== "AUTO") {
    return null;
}
let temperature = msg.payload.temperature;
let gas = msg.payload.gas_status;
let smoke = msg.payload.smoke_status;

let messages = [];

// 1. Gas leak automation
if (gas === "GAS_LEAK") {
    messages.push({
        topic: "home/kitchen/alarm/set",
        payload: "ON"
    });
}

// 2. Smoke / fire automation
if (smoke === "SMOKE_DETECTED") {
    messages.push({
        topic: "home/kitchen/alarm/set",
        payload: "ON"
    });
}

// 3. High temperature exhaust automation
if (temperature > 38) {
    messages.push({
        topic: "home/kitchen/exhaust/set",
        payload: "ON"
    });
}

if (temperature < 32 && gas === "NORMAL" && smoke === "NORMAL") {
    messages.push({
        topic: "home/kitchen/exhaust/set",
        payload: "OFF"
    });

    messages.push({
        topic: "home/kitchen/alarm/set",
        payload: "OFF"
    });
}

return [messages];

